body:
Add the MongoDB Node Driver as a dependency in your project:

```sh
npm install mongodb
```

> **Tip:** The examples on this page assume your project manages modules as
> CommonJS modules. If you're using ES modules, instead, you must
> modify the import syntax.

Create a file named `vector-index.js` and copy and paste the
following code into the file.

This index definition indexes the
`plot_embedding_voyage_3_large` field as the `vector` type and
the `genres` and `year` fields as the `filter` type in an
MongoDB Vector Search index. The `plot_embedding_voyage_3_large` field
contains embeddings created using Voyage AI's `voyage-3-large`
embedding model. The index definition specifies `2048` vector
dimensions and measures similarity using `dotProduct` function.

```javascript
const { MongoClient } = require("mongodb");

// connect to your deployment
const uri =  "<connectionString>";

const client = new MongoClient(uri);

async function run() {
   try {
     const database = client.db("sample_mflix");
     const collection = database.collection("embedded_movies");

     // define your MongoDB Vector Search index
     const index = {
         name: "vector_index",
         type: "vectorSearch",
         definition: {
           "fields": [
             {
               "type": "vector",
               "numDimensions": 2048,
               "path": "plot_embedding_voyage_3_large",
               "similarity": "dotProduct",
               "quantization": "scalar"
             },
             {
               "type": "filter",
               "path": "genres"
             },
             {
               "type": "filter",
               "path": "year"
             }
           ]
         }
     }

     // run the helper method
     const result = await collection.createSearchIndex(index);
     console.log(`New search index named ${result} is building.`);

     // wait for the index to be ready to query
     console.log("Polling to check if the index is ready. This may take up to a minute.")
     let isQueryable = false;
     while (!isQueryable) {
       const cursor = collection.listSearchIndexes();
       for await (const index of cursor) {
         if (index.name === result) {
           if (index.queryable) {
             console.log(`${result} is ready for querying.`);
             isQueryable = true;
           } else {
             await new Promise(resolve => setTimeout(resolve, 5000));
           }
         }
       }
     }
   } finally {
     await client.close();
   }
}
run().catch(console.dir);

```

Replace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.

**Input:**

```shell
node vector-index.js
```

**Output:**

```shell
vector_index
```

